<?php&#10;require_once 'db.php';&#10;&#10;global $pdo;&#10;$conn = $pdo;&#10;&#10;echo "Starting migration: Add violation form fields to motorists table\n\n";&#10;&#10;$new_columns = [&#10;    'address TEXT',&#10;    'driver_type VARCHAR(50)',&#10;    'nationality VARCHAR(50)',&#10;    'plate_number VARCHAR(20)',&#10;    'vehicle_year INTEGER',&#10;    'vehicle_color VARCHAR(30)',&#10;    'accident INTEGER DEFAULT 0'&#10;];&#10;&#10;$column_names = ['address', 'driver_type', 'nationality', 'plate_number', 'vehicle_year', 'vehicle_color', 'accident'];&#10;&#10;foreach ($column_names as $col) {&#10;    $result = $conn->query("PRAGMA table_info(motorists)");&#10;    $exists = false;&#10;    foreach ($result->fetchAll() as $row) {&#10;        if (trim($row['name']) === $col) {&#10;            $exists = true;&#10;            break;&#10;        }&#10;    }&#10;    if (!$exists) {&#10;        $conn->exec("ALTER TABLE motorists ADD COLUMN " . $col);&#10;        echo "✅ Added column: $col\n";&#10;    } else {&#10;        echo "ℹ️ Column $col already exists\n";&#10;    }&#10;}&#10;&#10;echo "\nMigration complete! New fields ready for use.\n";&#10;?>
